<!DOCTYPE html>
<html lang="id">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Program Kerja & SOP â€” IKPA PTA Medan</title>
<style>
  :root{
    --canvas:#eef3ef;--paper:#ffffff;--ink:#17231d;--muted:#56675e;--faint:#8c9a92;
    --line:#e3eae5;--green:#1f7a4d;--green-deep:#0f3324;--green-soft:#e9f3ed;--green-mid:#cfe3d8;
    --gold:#bf8f38;--blue:#3b7fc4;
  }
  *{box-sizing:border-box;margin:0;padding:0}
  html{scroll-behavior:smooth}
  body{font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif;background:var(--canvas);color:var(--ink);line-height:1.55;-webkit-font-smoothing:antialiased}
  a{color:inherit;text-decoration:none}
  .serif{font-family:Georgia,"Times New Roman",serif}

  /* Hero banner */
  .hero{position:relative;height:430px;background:url('data:image/png;base64,') center 42%/cover no-repeat;overflow:hidden}
  .hero::after{content:"";position:absolute;inset:0;background:linear-gradient(180deg,rgba(9,26,17,.62) 0%,rgba(9,26,17,.3) 42%,rgba(7,22,14,.7) 100%),linear-gradient(90deg,rgba(9,26,17,.5) 0%,rgba(9,26,17,.05) 55%)}
  .topbar{position:relative;z-index:3;max-width:1060px;margin:0 auto;padding:26px 28px;display:flex;align-items:center;justify-content:space-between;color:#fff}
  .brand{display:flex;align-items:center;gap:12px}
  .mark{width:40px;height:40px;border-radius:11px;background:rgba(255,255,255,.15);border:1px solid rgba(255,255,255,.32);display:flex;align-items:center;justify-content:center;font-size:18px}
  .brand b{display:block;font-size:13.5px;font-weight:700}
  .brand span{font-size:11px;color:rgba(255,255,255,.72)}
  .topbar .site{font-size:11.5px;letter-spacing:1.5px;text-transform:uppercase;color:rgba(255,255,255,.8)}
  .hero-c{position:relative;z-index:3;max-width:1060px;margin:0 auto;padding:16px 28px 0;text-align:center;color:#fff}
  .kick{display:inline-flex;align-items:center;gap:10px;font-size:11px;font-weight:700;letter-spacing:2.6px;text-transform:uppercase;color:rgba(255,255,255,.9);margin-top:20px}
  .kick::before,.kick::after{content:"";width:26px;height:1.5px;background:rgba(255,255,255,.55)}
  .hero-c h1{font-size:46px;line-height:1.1;letter-spacing:-.8px;font-weight:400;margin-top:16px;text-shadow:0 2px 30px rgba(0,0,0,.4)}
  .hero-c p{font-size:14.5px;color:rgba(255,255,255,.88);max-width:60ch;margin:14px auto 0;line-height:1.6;text-shadow:0 1px 16px rgba(0,0,0,.4)}

  /* Floating tabbed card */
  .stage{max-width:1000px;margin:-72px auto 64px;padding:0 28px;position:relative;z-index:5}
  .card{background:var(--paper);border:1px solid var(--line);border-radius:22px;box-shadow:0 30px 70px -30px rgba(15,50,33,.4);overflow:hidden}
  .tabs{display:flex;gap:6px;padding:14px;background:linear-gradient(180deg,#fbfdfb,#fff);border-bottom:1px solid var(--line)}
  .tab{flex:1;display:flex;align-items:center;justify-content:center;gap:9px;padding:13px 14px;border-radius:13px;font-size:13.5px;font-weight:700;color:var(--muted);cursor:pointer;transition:.16s;border:1px solid transparent}
  .tab .tn{font-family:Georgia,serif;font-size:12px;opacity:.6}
  .tab:hover{background:var(--green-soft);color:var(--green)}
  .tab.active{background:var(--green);color:#fff;box-shadow:0 8px 18px -6px rgba(31,122,77,.6)}
  .tab.active .tn{opacity:.8}
  .panel{display:none;padding:38px 42px 44px;animation:fade .3s ease}
  .panel.active{display:block}
  @keyframes fade{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:none}}

  .p-head{display:flex;align-items:baseline;justify-content:space-between;margin-bottom:6px}
  .p-head h2{font-family:Georgia,serif;font-size:24px;font-weight:400}
  .p-head .meta{font-size:12px;color:var(--faint)}
  .p-sub{font-size:13.5px;color:var(--muted);margin-bottom:24px;max-width:64ch}

  .feats{display:grid;grid-template-columns:1fr 1fr;gap:16px}
  .feat{position:relative;border:1px solid rgba(255,255,255,.14);border-radius:15px;padding:26px;overflow:hidden;transition:.18s;background:linear-gradient(140deg,rgba(4,18,11,.92) 0%,rgba(8,28,18,.52) 48%,rgba(26,68,45,.24) 100%),url('data:image/png;base64,') center/cover;color:#fff}
  .feat .yr{font-family:Georgia,serif;font-size:46px;color:rgba(255,255,255,.82);line-height:1;text-shadow:0 2px 18px rgba(0,0,0,.6)}
  .feat h3{font-size:16.5px;font-weight:700;margin-top:10px;color:#fff;text-shadow:0 1px 10px rgba(0,0,0,.5)}
  .feat p{font-size:12.5px;color:rgba(255,255,255,.86);margin-top:6px;text-shadow:0 1px 8px rgba(0,0,0,.45)}
  .feat a{display:inline-flex;gap:6px;margin-top:16px;font-size:12.5px;font-weight:700;color:#8fd9b1}
  .feat:hover{box-shadow:0 16px 34px rgba(9,30,20,.32);transform:translateY(-3px);border-color:rgba(255,255,255,.3)}

  .search{position:relative;display:flex;align-items:center;margin-bottom:20px}
  .search svg{position:absolute;left:15px;opacity:.4}
  .search input{width:100%;padding:12px 16px 12px 42px;font-size:14px;background:#fbfdfb;border:1px solid var(--line);border-radius:30px;outline:none;transition:.15s}
  .search input:focus{border-color:var(--green);box-shadow:0 0 0 3px var(--green-soft);background:#fff}

  .cols{columns:2;column-gap:38px}
  .group{break-inside:avoid;margin-bottom:22px}
  .gcap{display:flex;align-items:center;gap:9px;margin-bottom:6px}
  .gcap .gt{font-family:Georgia,serif;font-size:17px}
  .gcap .tag{font-size:9px;font-weight:700;letter-spacing:.6px;text-transform:uppercase;padding:3px 8px;border-radius:20px}
  .tag.anggaran{color:var(--green);background:var(--green-soft)}
  .tag.sakip{color:var(--gold);background:#f8f0da}
  .tag.kinerja{color:var(--blue);background:#e6f0fa}
  .row{display:flex;align-items:baseline;gap:11px;padding:10px 4px;border-bottom:1px solid var(--line);cursor:pointer;transition:.14s}
  .row:hover{padding-left:9px;background:linear-gradient(90deg,var(--green-soft),transparent)}
  .row .no{font-family:Georgia,serif;font-size:13px;color:var(--faint);width:26px;flex-shrink:0}
  .row:hover .no{color:var(--green)}
  .row .ti{font-size:13.5px;font-weight:600;line-height:1.3}
  .row .sumut{font-size:8.5px;font-weight:700;letter-spacing:.4px;color:var(--gold);background:#f8f0da;padding:2px 6px;border-radius:20px;text-transform:uppercase;margin-left:6px}
  .row .leader{flex:1;border-bottom:1.5px dotted var(--green-mid);transform:translateY(-4px);min-width:12px}
  .row .pg{font-size:10.5px;font-weight:600;color:var(--faint);flex-shrink:0}
  .empty{display:none;padding:22px 0;color:var(--faint);font-size:14px}

  .closing{display:grid;grid-template-columns:1.25fr 1fr;gap:16px}
  .jad{background:linear-gradient(150deg,var(--green),var(--green-deep));border-radius:16px;padding:28px;color:#fff;position:relative;overflow:hidden}
  .jad::after{content:"";position:absolute;right:-40px;top:-40px;width:140px;height:140px;border:1px solid rgba(255,255,255,.16);border-radius:50%}
  .jad .big{font-family:Georgia,serif;font-size:38px;line-height:1;opacity:.92}
  .jad h3{font-size:18px;font-weight:600;margin-top:12px}
  .jad p{font-size:12.5px;color:rgba(255,255,255,.82);margin-top:6px}
  .jad a{display:inline-flex;gap:7px;margin-top:18px;background:#fff;color:var(--green-deep);font-size:12.5px;font-weight:700;padding:10px 17px;border-radius:9px}
  .drive{background:#fbfdfb;border:1px solid var(--line);border-radius:16px;padding:28px;display:flex;flex-direction:column;justify-content:center}
  .drive .ic{font-size:26px}
  .drive h3{font-size:15.5px;font-weight:700;margin-top:12px}
  .drive p{font-size:12.5px;color:var(--muted);margin-top:6px}
  .drive a{display:inline-flex;gap:6px;margin-top:14px;font-size:12.5px;font-weight:700;color:var(--green)}

  .foot{text-align:center;color:var(--faint);font-size:12px;padding:0 28px 40px}
  .foot b{color:var(--muted);font-weight:600}

  @media(max-width:820px){
    .hero{height:380px}.hero-c h1{font-size:34px}
    .tabs{flex-direction:column}.tab{justify-content:flex-start}
    .panel{padding:26px 22px 30px}
    .feats,.closing,.cols{grid-template-columns:1fr;columns:1}
  }
</style>
</head>
<body>

  <header class="hero">
    <div class="topbar">
      <div class="brand"><div class="mark">âš–ï¸</div><div><b>IKPA Â· PTA Medan</b><span>Perencanaan, Program & Anggaran</span></div></div>
      <div class="site">Pengadilan Tinggi Agama Medan</div>
    </div>
    <div class="hero-c">
      <div class="kick">Sub Bagian Rencana Program & Anggaran</div>
      <h1 class="serif">Program Kerja & SOP</h1>
      <p>Ruang dokumen perencanaan yang tertata â€” rencana kerja, prosedur baku, dan jadwal kegiatan dalam satu tempat yang tenang dan mudah ditelusuri.</p>
    </div>
  </header>

  <div class="stage">
    <div class="card">
      <div class="tabs">
        <div class="tab" data-p="program"><span class="tn">01</span> Program Kerja</div>
        <div class="tab active" data-p="sop"><span class="tn">02</span> Standar Operasional (SOP)</div>
        <div class="tab" data-p="jadwal"><span class="tn">03</span> Jadwal & Arsip</div>
      </div>

      <section class="panel" id="program">
        <div class="p-head"><h2>Program Kerja</h2><span class="meta">2 dokumen</span></div>
        <p class="p-sub">Rencana kerja tahunan Sub Bagian Rencana Program dan Anggaran Pengadilan Tinggi Agama Medan.</p>
        <div class="feats">
          <div class="feat"><div class="yr serif">2024</div><h3>Program Kerja 2024</h3><p>Dokumen rencana kerja untuk tahun anggaran 2024.</p><a href="#">Buka dokumen â†’</a></div>
          <div class="feat"><div class="yr serif">2025</div><h3>Program Kerja 2025</h3><p>Pembaruan program kerja untuk tahun anggaran berjalan.</p><a href="#">Buka dokumen â†’</a></div>
        </div>
      </section>

      <section class="panel active" id="sop">
        <div class="p-head"><h2>Standard Operating Procedure</h2><span class="meta">14 dokumen</span></div>
        <p class="p-sub">Kumpulan prosedur baku, dikelompokkan menurut tahapan siklus perencanaan & anggaran.</p>
        <div class="search"><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="11" cy="11" r="7"/><path d="m21 21-4.3-4.3"/></svg><input id="q" type="text" placeholder="Cari prosedurâ€¦" oninput="filter()"></div>
        <div class="cols" id="toc"></div>
        <div class="empty" id="empty">Tidak ada prosedur yang cocok.</div>
      </section>

      <section class="panel" id="jadwal">
        <div class="p-head"><h2>Jadwal & Arsip</h2><span class="meta">Tahun 2025</span></div>
        <p class="p-sub">Linimasa pelaksanaan kegiatan serta arsip lengkap seluruh berkas.</p>
        <div class="closing">
          <div class="jad"><div class="big serif">2025</div><h3>Jadwal Kegiatan Tahun 2025</h3><p>Linimasa pelaksanaan kegiatan perencanaan program & anggaran sepanjang tahun.</p><a href="#">Buka jadwal â†’</a></div>
          <div class="drive"><div class="ic">ðŸ—‚ï¸</div><h3>Folder Google Drive</h3><p>Seluruh berkas SOP & program kerja tersimpan lengkap dan siap diunduh.</p><a href="#">Buka folder â†’</a></div>
        </div>
      </section>
    </div>
  </div>

  <div class="foot">Â© 2025 <b>Pengadilan Tinggi Agama Medan</b> Â· IKPA Â· Diperbarui 20 Juni 2024</div>

<script>
  const groups=[
    {cat:'anggaran',cap:'Perencanaan Anggaran',items:[
      {n:1,t:'Penyusunan Rencana Anggaran'},{n:2,t:'Rencana Anggaran (Baseline)',s:1},
      {n:3,t:'Penyusunan Pagu Indikatif'},{n:4,t:'Pagu Indikatif',s:1},
      {n:5,t:'Penyusunan Pagu Definitif'},{n:6,t:'Pagu Definitif',s:1},
      {n:7,t:'Anggaran Biaya Tambahan (ABT)'},{n:8,t:'Anggaran Biaya Tambahan (ABT)',s:1},
    ]},
    {cat:'sakip',cap:'Dokumen SAKIP',items:[
      {n:9,t:'Permintaan Dokumen SAKIP'},{n:10,t:'Penyusunan Dokumen SAKIP'},
      {n:11,t:'Penilaian & Evaluasi Dokumen SAKIP',s:1},
    ]},
    {cat:'kinerja',cap:'Kinerja & Monev',items:[
      {n:12,t:'Laporan E-Monev Bappenas'},{n:13,t:'Penyusunan Program Kerja'},
      {n:14,t:'Pengukuran & Pengumpulan Data Kinerja'},
    ]},
  ];
  const toc=document.getElementById('toc');
  groups.forEach(g=>{
    const wrap=document.createElement('div');wrap.className='group';wrap.dataset.cat=g.cat;
    wrap.innerHTML=`<div class="gcap"><span class="gt serif">${g.cap}</span><span class="tag ${g.cat}">${g.cat}</span></div>`;
    g.items.forEach(d=>{
      const r=document.createElement('div');r.className='row';
      r.dataset.text=(d.t+' '+(d.s?'se-sumut':'')).toLowerCase();
      r.innerHTML=`<span class="no">${String(d.n).padStart(2,'0')}</span><span class="ti">${d.t}`+(d.s?'<span class="sumut">se-Sumut</span>':'')+`</span><span class="leader"></span><span class="pg">PDF</span>`;
      wrap.appendChild(r);
    });
    toc.appendChild(wrap);
  });
  function filter(){
    const q=document.getElementById('q').value.toLowerCase().trim();let vis=0;
    document.querySelectorAll('.group').forEach(g=>{let s=0;g.querySelectorAll('.row').forEach(r=>{const ok=!q||r.dataset.text.includes(q);r.style.display=ok?'':'none';if(ok){s++;vis++;}});g.style.display=s?'':'none';});
    document.getElementById('empty').style.display=(q&&vis===0)?'block':'none';
  }
  document.querySelectorAll('.tab').forEach(t=>t.addEventListener('click',()=>{
    document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));
    document.querySelectorAll('.panel').forEach(x=>x.classList.remove('active'));
    t.classList.add('active');document.getElementById(t.dataset.p).classList.add('active');
  }));
</script>
</body>
</html>
